import axios from 'axios';
import { mockGames } from '../data/mockGames';

const API_BASE_URL = 'http://localhost:5000/api';

const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Add token to requests if available
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

// Initialize games in localStorage if not exists
const initializeGames = () => {
  if (!localStorage.getItem('games')) {
    localStorage.setItem('games', JSON.stringify(mockGames));
  }
};

initializeGames();

// Mock API responses using localStorage
const mockAPI = {
  getGames: (filters?: any) => {
    let games = JSON.parse(localStorage.getItem('games') || '[]');

    if (filters) {
      if (filters.platform) {
        games = games.filter((g: any) => g.platform === filters.platform);
      }
      if (filters.region) {
        games = games.filter((g: any) => g.region === filters.region);
      }
      if (filters.priceRange && filters.priceRange !== 'all') {
        switch (filters.priceRange) {
          case '0-25':
            games = games.filter((g: any) => g.price <= 25);
            break;
          case '25-50':
            games = games.filter((g: any) => g.price > 25 && g.price <= 50);
            break;
          case '50-100':
            games = games.filter((g: any) => g.price > 50 && g.price <= 100);
            break;
          case '100+':
            games = games.filter((g: any) => g.price > 100);
            break;
        }
      }

      if (filters.search) {
        const searchTerm = filters.search.toLowerCase();
        games = games.filter((g: any) => 
          g.title.toLowerCase().includes(searchTerm) || 
          g.description.toLowerCase().includes(searchTerm)
        );
      }
    }

    return Promise.resolve({ data: games });
  },

  getGame: (id: string) => {
    const games = JSON.parse(localStorage.getItem('games') || '[]');
    const game = games.find((g: any) => g._id === id);
    return Promise.resolve({ data: game });
  },

  createGame: (gameData: any) => {
    const games = JSON.parse(localStorage.getItem('games') || '[]');
    const newGame = {
      ...gameData,
      _id: Date.now().toString(),
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };
    games.push(newGame);
    localStorage.setItem('games', JSON.stringify(games));
    return Promise.resolve({ data: newGame });
  },

  updateGame: (id: string, gameData: any) => {
    const games = JSON.parse(localStorage.getItem('games') || '[]');
    const index = games.findIndex((g: any) => g._id === id);
    if (index !== -1) {
      games[index] = { ...games[index], ...gameData, updatedAt: new Date().toISOString() };
      localStorage.setItem('games', JSON.stringify(games));
      return Promise.resolve({ data: games[index] });
    }
    return Promise.reject(new Error('Game not found'));
  },

  deleteGame: (id: string) => {
    let games = JSON.parse(localStorage.getItem('games') || '[]');
    games = games.filter((g: any) => g._id !== id);
    localStorage.setItem('games', JSON.stringify(games));
    return Promise.resolve({ data: { success: true } });
  },
};

// Auth APIs
export const authAPI = {
  login: (email: string, password: string) => api.post('/auth/login', { email, password }),
  register: (userData: any) => api.post('/auth/register', userData),
  verifyToken: () => api.get('/auth/verify'),
  googleAuth: (code: string) => api.post('/auth/google', { code }),
};

// Games APIs - Use localStorage mock
export const gamesAPI = {
  getGames: (filters?: any) => mockAPI.getGames(filters),
  getGame: (id: string) => mockAPI.getGame(id),
  createGame: (gameData: any) => mockAPI.createGame(gameData),
  updateGame: (id: string, gameData: any) => mockAPI.updateGame(id, gameData),
  deleteGame: (id: string) => mockAPI.deleteGame(id),
};

// Orders APIs
export const ordersAPI = {
  createOrder: (orderData: any) => api.post('/orders', orderData),
  getMyOrders: () => api.get('/orders/my-orders'),
  getAllOrders: () => api.get('/orders'),
  updateOrderStatus: (id: string, status: string) => api.put(`/orders/${id}/status`, { status }),
};

// Admin APIs - Use localStorage mock for games
export const adminAPI = {
  getDashboard: () => api.get('/admin/dashboard'),
  getUsers: () => api.get('/admin/users'),
  getOrders: () => api.get('/admin/orders'),
  getGames: () => mockAPI.getGames(),
  updateOrderStatus: (id: string, status: string) => api.put(`/admin/orders/${id}/status`, { status }),
};

// Upload APIs
export const uploadAPI = {
  uploadImage: (file: File) => {
    const formData = new FormData();
    formData.append('image', file);
    return api.post('/upload/image', formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      },
    });
  },
  uploadImages: (files: File[]) => {
    const formData = new FormData();
    files.forEach((file, index) => {
      formData.append(`images`, file);
    });
    return api.post('/upload/images', formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      },
    });
  },
};

export default api;
